mapper.select:
SELECT DATE_FORMAT(date, '%Y-%m-%d')
FROM station_date
WHERE station = #{station}

SELECT LPAD(MONTH(date), 2, '0') AS month, COUNT(*) AS total
FROM station_date
WHERE station = #{station}
  AND YEAR(date) = #{year}
GROUP BY MONTH(date)
HAVING COUNT(*) > 0

SELECT LPAD(DAY(date), 2, '0') AS day, COUNT(*) AS total
FROM station_date
WHERE station = #{station}
  AND YEAR(date) = #{year}
  AND MONTH(date) = #{month}
GROUP BY DAY(date)
HAVING COUNT(*) > 0

SELECT DATE_FORMAT(date, '%Y-%m-%d') AS day, COUNT(*) AS total
FROM ${tableName}
WHERE DATE_FORMAT(date, '%Y-%m') = #{month}
GROUP BY DATE_FORMAT(date, '%Y-%m-%d')
ORDER BY day DESC
